/**
 * TalentDrawDemoSelectionFlowRuleSelectionFlow
 * 选择流程管理器 - Generated by Rune Weaver
 *
 * Features:
 * - choiceCount: 3
 * - selectionPolicy: "single"
 * - applyMode: "immediate"
 * - postSelectionPoolBehavior: "remove_selected_from_remaining"
 * - trackSelectedItems: true
 */

interface SelectionOption {
  id: string;
  name: string;
  description: string;
  icon?: string;
  tier?: string;
}

interface PoolCandidate {
  id: string;
  name?: string;
  label?: string;
  description?: string;
  icon?: string;
  tier?: string;
}

interface PoolCommitOptions {
  trackOwned?: boolean;
}

interface SelectionOutcomeHandlerResult {
  handled: boolean;
}

interface SelectionWorldPosition {
  x: number;
  y: number;
  z: number;
}

interface SelectionOutcomeRequest {
  featureId: string;
  playerId: number;
  option: SelectionOption;
  cursorPosition?: SelectionWorldPosition;
}

interface PlayerSelection {
  playerId: number;
  options: SelectionOption[];
  selectedIndex: number;
  isConfirmed: boolean;
  deferredEffect?: SelectionOption;
  poolCommit?: (selectedId: string, options?: PoolCommitOptions) => void;
}

export class TalentDrawDemoSelectionFlowRuleSelectionFlow {
  private static instance: TalentDrawDemoSelectionFlowRuleSelectionFlow;
  private activeSelections: Map<number, PlayerSelection> = new Map();
  private selectionCallbacks: Map<number, (option: SelectionOption) => void> = new Map();
  private selectionOutcomeHandlers: Array<
    (context: SelectionOutcomeRequest & { request: SelectionOutcomeRequest }) => SelectionOutcomeHandlerResult | void
  > = [];

  static getInstance(): TalentDrawDemoSelectionFlowRuleSelectionFlow {
    if (!TalentDrawDemoSelectionFlowRuleSelectionFlow.instance) {
      TalentDrawDemoSelectionFlowRuleSelectionFlow.instance = new TalentDrawDemoSelectionFlowRuleSelectionFlow();
    }
    return TalentDrawDemoSelectionFlowRuleSelectionFlow.instance;
  }

  startSelection(
    playerId: number,
    options: SelectionOption[],
    onSelected: (option: SelectionOption) => void,
    poolCommit?: (selectedId: string, options?: PoolCommitOptions) => void
  ): void {
    if (options.length === 0) {
      print("[Rune Weaver] Cannot start selection with empty options");
      return;
    }

    this.activeSelections.set(playerId, {
      playerId,
      options,
      selectedIndex: -1,
      isConfirmed: false,
      poolCommit,
    });
    this.selectionCallbacks.set(playerId, onSelected);
    this.sendToClient(playerId, options);
  }

  registerOutcomeHandler(
    handler: (context: SelectionOutcomeRequest & { request: SelectionOutcomeRequest }) => SelectionOutcomeHandlerResult | void
  ): void {
    this.selectionOutcomeHandlers.push(handler);
  }

  onPlayerSelect(playerId: number, optionIndex: number): void {
    const selection = this.activeSelections.get(playerId);
    if (!selection) return;
    if (optionIndex < 0 || optionIndex >= selection.options.length) return;

    selection.selectedIndex = optionIndex;
    this.fireSelectionEvent(playerId, selection.options[optionIndex]);
  }

  onPlayerConfirm(playerId: number, confirmContext?: { cursorPosition?: SelectionWorldPosition }): void {
    const selection = this.activeSelections.get(playerId);
    if (!selection || selection.selectedIndex === -1) return;

    selection.isConfirmed = true;
    const selectedOption = selection.options[selection.selectedIndex];

    if (selection.poolCommit) {
      selection.poolCommit(selectedOption.id, { trackOwned: true });
    }
    const outcomeRequest: SelectionOutcomeRequest = {
      featureId: "talent_draw_demo",
      playerId,
      option: selectedOption,
      ...(confirmContext?.cursorPosition ? { cursorPosition: confirmContext.cursorPosition } : {}),
    };
    this.handleSelectionOutcome(outcomeRequest);

    const callback = this.selectionCallbacks.get(playerId);
    if (callback) {
      callback(selectedOption);
    }

    this.fireConfirmationEvent(playerId, selectedOption);
    this.activeSelections.delete(playerId);
    this.selectionCallbacks.delete(playerId);
  }

  private fireSelectionEvent(playerId: number, option: SelectionOption): void {
    if (CustomGameEventManager) {
      (CustomGameEventManager.Send_ServerToPlayer as any)(
        PlayerResource.GetPlayer(playerId as PlayerID),
        "rune_weaver_selection_made",
        {
          featureId: "talent_draw_demo",
          optionId: option.id,
          optionName: option.name,
          rarity: option.tier || "R",
        }
      );
    }
  }

  private handleSelectionOutcome(request: SelectionOutcomeRequest): boolean {
    for (const handler of this.selectionOutcomeHandlers) {
      const result = handler({ ...request, request });
      if (result && result.handled === true) {
        return true;
      }
    }

    return false;
  }

  private fireConfirmationEvent(playerId: number, option: SelectionOption): void {
    if (CustomGameEventManager) {
      (CustomGameEventManager.Send_ServerToPlayer as any)(
        PlayerResource.GetPlayer(playerId as PlayerID),
        "rune_weaver_selection_confirmed",
        {
          featureId: "talent_draw_demo",
          optionId: option.id,
          optionName: option.name,
          rarity: option.tier || "R",
          timestamp: GameRules.GetGameTime(),
        }
      );
    }
  }

  private sendToClient(playerId: number, options: SelectionOption[]): void {
    if ((GameRules as any).XNetTable) {
      (GameRules as any).XNetTable.SetTableValue(
        "rune_weaver_selection",
        `player_${playerId}_feature_talent_draw_demo`,
        {
          featureId: "talent_draw_demo",
          options,
          status: "waiting",
        }
      );
    }

    if (CustomGameEventManager) {
      const payload = {
        featureId: "talent_draw_demo",
        options,
        choiceCount: 3,
        selectionPolicy: "single",
      };
      const player = PlayerResource.GetPlayer(playerId as PlayerID);
      print(`[Rune Weaver] TalentDrawDemoSelectionFlowRuleSelectionFlow: sending selection UI to player ${playerId}, options=${options.length}, player=${player ? "ok" : "missing"}`);
      if (player) {
        (CustomGameEventManager.Send_ServerToPlayer as any)(
          player,
          "rune_weaver_show_selection",
          payload
        );
      } else {
        (CustomGameEventManager.Send_ServerToAllClients as any)(
          "rune_weaver_show_selection",
          payload
        );
      }
    }
  }

  generateOptionsFromPool<T extends SelectionOption>(
    pool: any,
    count: number
  ): T[] {
    const normalizeCandidates = (candidates: PoolCandidate[]): T[] => {
      return candidates.map((candidate) => ({
        id: candidate.id,
        name: candidate.name || candidate.label || candidate.id,
        description: candidate.description || "",
        icon: candidate.icon,
        tier: candidate.tier,
      })) as T[];
    };

    if (pool && typeof pool.drawForSelection === "function") {
      return normalizeCandidates(pool.drawForSelection(count) as PoolCandidate[]);
    }

    if (pool && typeof pool.drawMultiple === "function") {
      return normalizeCandidates(pool.drawMultiple(count) as PoolCandidate[]);
    }

    return [];
  }

  triggerSelectionFromPool(playerId: number, pool: any): void {
    if (!pool) {
      print(`[Rune Weaver] TalentDrawDemoSelectionFlowRuleSelectionFlow: no pool available`);
      return;
    }

    const options = this.generateOptionsFromPool(pool, 3);
    if (!options || options.length === 0) {
      print(`[Rune Weaver] TalentDrawDemoSelectionFlowRuleSelectionFlow: no options generated for player ${playerId}`);
      return;
    }

    this.startSelection(
      playerId,
      options,
      () => {},

      pool && typeof pool.commitSelection === "function"
        ? (selectedId, options) => pool.commitSelection(selectedId, options)
        : undefined
    );
  }
}

export function registerTalentDrawDemoSelectionFlowRuleSelectionFlow(): void {
  const flow = TalentDrawDemoSelectionFlowRuleSelectionFlow.getInstance();
  print("[Rune Weaver] TalentDrawDemoSelectionFlowRuleSelectionFlow registered");

  if (CustomGameEventManager) {
    CustomGameEventManager.RegisterListener("rune_weaver_player_select", (_eventSourceIndex: number, event: any) => {
      if (event.featureId && event.featureId !== "talent_draw_demo") {
        return;
      }
      const playerId = Number(event.PlayerID ?? event.playerId ?? -1);
      const optionIndex = Number(event.optionIndex ?? -1);
      if (playerId >= 0 && optionIndex >= 0) {
        flow.onPlayerSelect(playerId, optionIndex);
      }
    });

    CustomGameEventManager.RegisterListener("rune_weaver_player_confirm", (_eventSourceIndex: number, event: any) => {
      if (event.featureId && event.featureId !== "talent_draw_demo") {
        return;
      }
      const playerId = Number(event.PlayerID ?? event.playerId ?? -1);
      const hasCursorPosition =
        Number.isFinite(Number(event.cursorX)) &&
        Number.isFinite(Number(event.cursorY));
      if (playerId >= 0) {
        flow.onPlayerConfirm(
          playerId,
          hasCursorPosition
            ? {
                cursorPosition: {
                  x: Number(event.cursorX),
                  y: Number(event.cursorY),
                  z: Number.isFinite(Number(event.cursorZ)) ? Number(event.cursorZ) : 0,
                },
              }
            : undefined,
        );
      }
    });
  }
}

/**
 * TalentDrawDemoWeightedPoolDataWeightedPool
 * 加权随机池 - Generated by Rune Weaver
 *
 * Features:
 * - drawMode: multiple_without_replacement
 * - duplicatePolicy: forbid
 * - poolStateTracking: session
 */

interface SelectionPoolEntry {
  id: string;
  label: string;
  description: string;
  weight: number;
  tier?: string;
}

interface WeightedItem<T> {
  item: T;
  weight: number;
  tier?: number;
}

export class TalentDrawDemoWeightedPoolDataWeightedPool<T extends SelectionPoolEntry = SelectionPoolEntry> {
  private static instance?: TalentDrawDemoWeightedPoolDataWeightedPool<any>;
  private items: WeightedItem<T>[] = [];
  private totalWeight: number = 0;

  private sessionState: {
    remainingObjectIds: string[];
    ownedObjectIds: string[];
    currentChoiceIds: string[];
  } = {
    remainingObjectIds: [],
    ownedObjectIds: [],
    currentChoiceIds: [],
  };

  static getInstance<U extends SelectionPoolEntry = SelectionPoolEntry>(): TalentDrawDemoWeightedPoolDataWeightedPool<U> {
    if (!TalentDrawDemoWeightedPoolDataWeightedPool.instance) {
      TalentDrawDemoWeightedPoolDataWeightedPool.instance = new TalentDrawDemoWeightedPoolDataWeightedPool<U>();
    }
    return TalentDrawDemoWeightedPoolDataWeightedPool.instance as TalentDrawDemoWeightedPoolDataWeightedPool<U>;
  }

  constructor() {
    const initialEntries = [
    { id: "SEL_R001", label: "Talent Option R001", description: "Placeholder selection option (R)", weight: 40, tier: "R" },
    { id: "SEL_R002", label: "Talent Option R002", description: "Placeholder selection option (R)", weight: 40, tier: "R" },
    { id: "SEL_SR003", label: "Talent Option SR003", description: "Placeholder selection option (SR)", weight: 30, tier: "SR" },
    { id: "SEL_SR004", label: "Talent Option SR004", description: "Placeholder selection option (SR)", weight: 30, tier: "SR" },
    { id: "SEL_SSR005", label: "Talent Option SSR005", description: "Placeholder selection option (SSR)", weight: 20, tier: "SSR" },
    { id: "SEL_UR006", label: "Talent Option UR006", description: "Placeholder selection option (UR)", weight: 10, tier: "UR" }
    ] as T[];
    for (const entry of initialEntries) {
      this.add(entry, entry.weight, entry.tier ? this.tierToNumber(entry.tier) : 0);
    }
    this.sessionState.remainingObjectIds = initialEntries.map((item) => item.id);
    this.sessionState.ownedObjectIds = [];
    this.sessionState.currentChoiceIds = [];

  }

  private tierToNumber(tier: string): number {
    const tierMap: Record<string, number> = { R: 1, SR: 2, SSR: 4, UR: 7 };
    return tierMap[tier] || 1;
  }

  private pickWeightedItem(candidates: WeightedItem<T>[]): WeightedItem<T> | null {
    if (candidates.length === 0) {
      return null;
    }

    const totalWeight = candidates.reduce((sum, candidate) => sum + candidate.weight, 0);
    if (totalWeight <= 0) {
      return null;
    }

    let random = RandomFloat(0, totalWeight);
    for (const candidate of candidates) {
      random -= candidate.weight;
      if (random <= 0) {
        return candidate;
      }
    }

    return candidates[candidates.length - 1] || null;
  }

  private getAvailableItems(): WeightedItem<T>[] {
    return this.items.filter((candidate) =>
      this.sessionState.remainingObjectIds.includes((candidate.item as any).id)
    );
  }

  add(item: T, weight: number, tier?: number): void {
    this.items.push({ item, weight, tier });
    this.totalWeight += weight;
  }

  remove(item: T): boolean {
    const index = this.items.findIndex((candidate) => candidate.item === item);
    if (index === -1) {
      return false;
    }

    this.totalWeight -= this.items[index].weight;
    this.items.splice(index, 1);
    return true;
  }

  clear(): void {
    this.items = [];
    this.totalWeight = 0;
    this.sessionState.remainingObjectIds = [];
    this.sessionState.ownedObjectIds = [];
    this.sessionState.currentChoiceIds = [];
  }

  draw(): T | null {
    const drawn = this.pickWeightedItem(this.items);
    return drawn ? drawn.item : null;
  }

  drawMultiple(count: number): T[] {
    const requestedCount = Math.max(1, Math.floor(count));
    const result: T[] = [];
    const workingItems = [...this.items];

    while (result.length < requestedCount && workingItems.length > 0) {
      const drawn = this.pickWeightedItem(workingItems);
      if (!drawn) {
        break;
      }

      result.push(drawn.item);
      const index = workingItems.indexOf(drawn);
      if (index >= 0) {
        workingItems.splice(index, 1);
      }
    }

    return result;
  }

  /**
   * GAP_FILL_BOUNDARY: weighted_pool.selection_policy
   * Allowed: weighted draw policy details, duplicate handling, session-aware filtering.
   * Forbidden: pool contract changes, host routing changes, undeclared persistence semantics.
   */
  drawForSelection(count: number = 3): T[] {
    const requestedCount = Math.max(1, Math.floor(count));
    const result: T[] = [];
    const configuredDrawMode: string = "multiple_without_replacement";
    const configuredDuplicatePolicy: string = "forbid";
    const allowReplacement =
      configuredDrawMode === "multiple_with_replacement" && configuredDuplicatePolicy === "allow";
    const workingItems = this.getAvailableItems();

    if (workingItems.length === 0) {
      print(`[Rune Weaver] TalentDrawDemoWeightedPoolDataWeightedPool: no available items in pool`);
      return [];
    }

    while (result.length < requestedCount && workingItems.length > 0) {
      const drawn = this.pickWeightedItem(workingItems);
      if (!drawn) {
        break;
      }

      result.push(drawn.item);

      if (configuredDrawMode === "single") {
        break;
      }

      if (!allowReplacement) {
        const drawnId = (drawn.item as any).id;
        for (let index = workingItems.length - 1; index >= 0; index -= 1) {
          if ((workingItems[index].item as any).id === drawnId) {
            workingItems.splice(index, 1);
          }
        }
      }
    }

    this.sessionState.currentChoiceIds = result.map((item) => (item as any).id);

    return result;
  }

  commitSelection(selectedId: string, options?: { trackOwned?: boolean }): void {
    const remainingIndex = this.sessionState.remainingObjectIds.indexOf(selectedId);
    if (remainingIndex > -1) {
      this.sessionState.remainingObjectIds.splice(remainingIndex, 1);
    }

    if (options?.trackOwned !== false && !this.sessionState.ownedObjectIds.includes(selectedId)) {
      this.sessionState.ownedObjectIds.push(selectedId);
    }

    this.sessionState.currentChoiceIds = [];

    print(
      `[Rune Weaver] TalentDrawDemoWeightedPoolDataWeightedPool: committed selection ${selectedId}, remaining=${this.sessionState.remainingObjectIds.length}`
    );
  }

  getRemainingObjectIds(): string[] {
    return [...this.sessionState.remainingObjectIds];
  }

  getOwnedObjectIds(): string[] {
    return [...this.sessionState.ownedObjectIds];
  }

  getCurrentChoiceIds(): string[] {
    return [...this.sessionState.currentChoiceIds];
  }

  resetSessionState(): void {
    this.sessionState.remainingObjectIds = this.items.map((item) => (item.item as any).id);
    this.sessionState.ownedObjectIds = [];
    this.sessionState.currentChoiceIds = [];
    print(`[Rune Weaver] TalentDrawDemoWeightedPoolDataWeightedPool: session state reset`);
  }

  drawByTier(tier: number): T | null {
    const tierItems = this.items.filter((candidate) => candidate.tier === tier);
    const drawn = this.pickWeightedItem(tierItems);
    return drawn ? drawn.item : null;
  }

  getAllItems(): WeightedItem<T>[] {
    return [...this.items];
  }

  getCount(): number {
    return this.items.length;
  }
}

export function registerTalentDrawDemoWeightedPoolDataWeightedPool(): void {
  TalentDrawDemoWeightedPoolDataWeightedPool.getInstance();
  print("[Rune Weaver] TalentDrawDemoWeightedPoolDataWeightedPool registered");
}

/**
 * TalentDrawDemoSelectionOutcomeEffectOutcomeRealizer
 * 选择结果宿主实现层 - Generated by Rune Weaver
 */

interface SelectionOption {
  id: string;
  name: string;
  description: string;
  icon?: string;
  tier?: string;
}

interface SelectionWorldPosition {
  x: number;
  y: number;
  z: number;
}

interface SelectionOutcomeRequest {
  featureId: string;
  playerId: number;
  option: SelectionOption;
  cursorPosition?: SelectionWorldPosition;
}

interface SelectionOutcomeHandlerResult {
  handled: boolean;
}

interface AttributeBonusOutcomeSpec {
  kind: "attribute_bonus";
  attribute: "strength" | "agility" | "intelligence" | "all";
  value: number;
}

interface NativeItemDeliveryOutcomeSpec {
  kind: "native_item_delivery";
  itemName: string;
  deliveryMode: "hero_inventory" | "ground_drop";
  fallbackWhenInventoryFull: "drop_to_ground" | "skip_delivery";
  positionPolicy: "hero_origin" | "hero_forward" | "cursor_point";
}

interface SpawnUnitOutcomeSpec {
  kind: "spawn_unit";
  unitName: string;
  spawnCount?: number;
  positionPolicy: "hero_origin" | "hero_forward" | "cursor_point";
  teamScope?: "player_team";
}

type OutcomeSpec =
  | AttributeBonusOutcomeSpec
  | NativeItemDeliveryOutcomeSpec
  | SpawnUnitOutcomeSpec;

type SelectionFlowLike = {
  registerOutcomeHandler: (
    handler: (context: SelectionOutcomeRequest & { request?: SelectionOutcomeRequest }) => SelectionOutcomeHandlerResult | void
  ) => void;
};

export class TalentDrawDemoSelectionOutcomeEffectOutcomeRealizer {
  private static instance: TalentDrawDemoSelectionOutcomeEffectOutcomeRealizer;
  private attached = false;
  private outcomesById: Record<string, OutcomeSpec> = {

  };

  static getInstance(): TalentDrawDemoSelectionOutcomeEffectOutcomeRealizer {
    if (!TalentDrawDemoSelectionOutcomeEffectOutcomeRealizer.instance) {
      TalentDrawDemoSelectionOutcomeEffectOutcomeRealizer.instance = new TalentDrawDemoSelectionOutcomeEffectOutcomeRealizer();
    }
    return TalentDrawDemoSelectionOutcomeEffectOutcomeRealizer.instance;
  }

  attachToSelectionFlow(selectionFlow: SelectionFlowLike | undefined): void {
    if (!selectionFlow || typeof selectionFlow.registerOutcomeHandler !== "function" || this.attached) {
      return;
    }

    selectionFlow.registerOutcomeHandler((context) => {
      const request = context.request || context;
      const handled = this.handleOutcomeRequest(request);
      return { handled };
    });
    this.attached = true;
    print("[Rune Weaver] TalentDrawDemoSelectionOutcomeEffectOutcomeRealizer: attached to selection flow for feature talent_draw_demo");
  }

  private handleOutcomeRequest(request: SelectionOutcomeRequest): boolean {
    const outcome = this.outcomesById[request.option.id];
    if (!outcome) {
      return false;
    }

    switch (outcome.kind) {
      case "attribute_bonus":
        this.realizeAttributeBonus(request, outcome);
        return true;
      case "native_item_delivery":
        this.realizeNativeItemDelivery(request, outcome);
        return true;
      case "spawn_unit":
        this.realizeSpawnUnit(request, outcome);
        return true;
      default:
        print(`[Rune Weaver] TalentDrawDemoSelectionOutcomeEffectOutcomeRealizer: unknown outcome kind for ${request.option.id}`);
        return true;
    }
  }

  private resolveHero(playerId: number): CDOTA_BaseNPC_Hero | undefined {
    const hero = PlayerResource.GetSelectedHeroEntity(playerId as PlayerID);
    if (!hero) {
      print(`[Rune Weaver] TalentDrawDemoSelectionOutcomeEffectOutcomeRealizer: no hero found for player ${playerId}`);
      return undefined;
    }
    return hero;
  }

  private resolveItemOwner(playerId: number): CDOTAPlayerController | undefined {
    return PlayerResource.GetPlayer(playerId as PlayerID);
  }

  private emitAttributeBonusEvent(
    request: SelectionOutcomeRequest,
    outcome: AttributeBonusOutcomeSpec,
  ): void {
    const player = PlayerResource.GetPlayer(request.playerId as PlayerID);
    if (!player || !CustomGameEventManager) {
      return;
    }

    (CustomGameEventManager.Send_ServerToPlayer as any)(
      player,
      "rune_weaver_effect_applied",
      {
        featureId: "talent_draw_demo",
        optionId: request.option.id,
        optionName: request.option.name,
        attribute: outcome.attribute,
        value: outcome.value,
        rarity: request.option.tier || "R",
      }
    );
  }

  private realizeAttributeBonus(
    request: SelectionOutcomeRequest,
    outcome: AttributeBonusOutcomeSpec,
  ): void {
    const hero = this.resolveHero(request.playerId);
    if (!hero) {
      return;
    }

    switch (outcome.attribute) {
      case "strength":
        hero.ModifyStrength(outcome.value);
        break;
      case "agility":
        hero.ModifyAgility(outcome.value);
        break;
      case "intelligence":
        hero.ModifyIntellect(outcome.value);
        break;
      case "all":
        hero.ModifyStrength(outcome.value);
        hero.ModifyAgility(outcome.value);
        hero.ModifyIntellect(outcome.value);
        break;
      default:
        print(`[Rune Weaver] TalentDrawDemoSelectionOutcomeEffectOutcomeRealizer: unknown attribute ${outcome.attribute}`);
        return;
    }

    this.emitAttributeBonusEvent(request, outcome);
  }

  private resolveBoundedPosition(
    hero: CDOTA_BaseNPC_Hero,
    request: SelectionOutcomeRequest,
    positionPolicy: "hero_origin" | "hero_forward" | "cursor_point",
    index: number = 0,
  ): Vector {
    const origin = hero.GetAbsOrigin();
    const forward = hero.GetForwardVector();
    const lateralX = -forward.y;
    const lateralY = forward.x;
    const spreadCenter =
      index <= 0
        ? 0
        : (index % 2 === 0 ? 1 : -1) * Math.ceil(index / 2) * 96;

    if (positionPolicy === "cursor_point" && request.cursorPosition) {
      return Vector(
        request.cursorPosition.x + lateralX * spreadCenter,
        request.cursorPosition.y + lateralY * spreadCenter,
        request.cursorPosition.z,
      );
    }

    if (positionPolicy === "hero_forward") {
      return Vector(
        origin.x + forward.x * 160 + lateralX * spreadCenter,
        origin.y + forward.y * 160 + lateralY * spreadCenter,
        origin.z,
      );
    }

    return Vector(
      origin.x + lateralX * spreadCenter,
      origin.y + lateralY * spreadCenter,
      origin.z,
    );
  }

  private hasAvailableInventorySlot(hero: CDOTA_BaseNPC_Hero): boolean {
    for (let slot = 0; slot < 6; slot += 1) {
      if (!hero.GetItemInSlot(slot)) {
        return true;
      }
    }
    return false;
  }

  private dropItemAtPosition(
    owner: CDOTAPlayerController | undefined,
    hero: CDOTA_BaseNPC_Hero,
    itemName: string,
    position: Vector,
  ): void {
    const item = CreateItem(itemName, owner, hero);
    if (!item) {
      print(`[Rune Weaver] TalentDrawDemoSelectionOutcomeEffectOutcomeRealizer: failed to create item ${itemName}`);
      return;
    }
    CreateItemOnPositionSync(position, item);
  }

  private realizeNativeItemDelivery(
    request: SelectionOutcomeRequest,
    outcome: NativeItemDeliveryOutcomeSpec,
  ): void {
    const hero = this.resolveHero(request.playerId);
    const owner = this.resolveItemOwner(request.playerId);
    if (!hero) {
      return;
    }

    if (outcome.deliveryMode === "ground_drop") {
      this.dropItemAtPosition(owner, hero, outcome.itemName, this.resolveBoundedPosition(hero, request, outcome.positionPolicy));
      return;
    }

    if (this.hasAvailableInventorySlot(hero)) {
      const item = CreateItem(outcome.itemName, owner, hero);
      if (!item) {
        print(`[Rune Weaver] TalentDrawDemoSelectionOutcomeEffectOutcomeRealizer: failed to create item ${outcome.itemName}`);
        return;
      }
      hero.AddItem(item);
      return;
    }

    if (outcome.fallbackWhenInventoryFull === "drop_to_ground") {
      this.dropItemAtPosition(owner, hero, outcome.itemName, this.resolveBoundedPosition(hero, request, outcome.positionPolicy));
      return;
    }

    print(`[Rune Weaver] TalentDrawDemoSelectionOutcomeEffectOutcomeRealizer: inventory full, skipped item delivery for ${outcome.itemName}`);
  }

  private realizeSpawnUnit(
    request: SelectionOutcomeRequest,
    outcome: SpawnUnitOutcomeSpec,
  ): void {
    const hero = this.resolveHero(request.playerId);
